    ans := make([]int64, len(queries))
    for i, q := range queries {
        l := q[0]
        r := q[1]
        t := q[2]
        subLen := r - l + 1
        if t > subLen {
            ans[i] = -1
            continue
        }
        freq := make(map[int64]int64)
        for j := l; j <= r; j++ {
            num := nums[j]
            freq[num]++
        }
        maxFreq := 0
        bestNum := -1
        for num, cnt := range freq {
            if cnt > maxFreq || (cnt == maxFreq && num < bestNum) {
                maxFreq = cnt
                bestNum = num
            }
        }
        if maxFreq >= t {
            ans[i] = bestNum
        } else {
            ans[i] = -1
        }
    }
    return ans
}
